INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('c0ad270e-6898-58f4-b4a5-fd2e267343a9', '612e4929-f4a2-437a-b76f-0062b45fc9d2', 'The summer internship program is set to start on ___ 12th, so please submit your application before then.', '暑期實習計畫定於八月十二日開始，所以請在那之前提交申請。', 'Aug.', 'Jan.', 'Oct.', 'Dec.', 'Aug. 是 August (八月) 的縮寫。', '記住 August 的前三個字母加上句點 → Aug. 代表八月。', '2026-07-07 03:32:28', '2026-07-07 03:32:28'),
('0ca2b978-27a3-5aa7-9c33-32e1b4499f4d', 'da6e0056-ea34-495b-8df5-fd9d348e75a4', 'If you make a serious mistake at work, you must be ___ for the consequences.', '如果你在工作上犯了嚴重的錯誤，你必須對後果負責。', 'accountable', 'capable', 'eligible', 'available', 'account (帳目/說明) + able (能夠...的) → 能夠被說明的 → 應負責任的。', '想像在帳本 (account) 上清楚記錄每一筆支出，讓你必須為結果負責 → accountable。', '2026-07-06 16:56:22', '2026-07-06 16:56:22'),
('9579bead-114b-5aba-8ee4-70d084b28875', '6ab23f02-d5c3-4fb0-a1cf-5b52476385dd', 'The shop is ___ the street from the station.', '那間商店在車站對面的街道上。', 'across', 'beside', 'inside', 'behind', 'a- (表示趨向) + cross (橫越) → 橫越、在對面', 'across → 橫向跨越 → 在對面', '2026-07-06 12:52:40', '2026-07-06 12:52:40'),
('4c883576-d52b-547b-92bd-cc9db72dfd01', 'cc0fd6e4-b144-46c1-947b-430e8170919d', 'The government must take immediate ___ to address the rising pollution levels in the city.', '政府必須立即採取行動來解決城市中日益嚴重的污染問題。', 'action', 'attention', 'advantage', 'advice', 'act (做/行動) + ion (名詞字尾) → 動作/行動', 'take action 是「採取行動」；pay attention 是「注意」；take advantage of 是「利用」。', '2026-07-06 17:22:57', '2026-07-06 17:22:57'),
('872677ea-e9c4-52cb-95cc-7d0f8f1bc671', 'e0ae7c02-3834-46ea-8989-78bb4f861d18', 'A rainbow will ___ in the sky after the rain.', '雨後，天空中會出現一道彩虹。', 'appear', 'eat', 'sleep', 'cook', 'ap- 表示「向」，pear 表示「顯現」。', 'ap (向) + pear (顯現) → 向著你看 → 出現', '2026-07-06 14:34:48', '2026-07-06 14:34:48'),
('7397bdb7-c024-58af-bb11-74794d4dff69', '23c3030b-3bcb-42a1-8455-79df4c54817e', 'It is important not to judge others based only on their outward ___.', '不要僅僅根據他人的外表來評判他人是很重要的。', 'appearance', 'behavior', 'strength', 'opinion', 'appear (出現) + -ance (名詞字尾) → appearance (外貌；出現)', '想像演員在舞台上 appear (出現)，觀眾看到的即是他的 appearance (外貌)。', '2026-07-06 22:57:32', '2026-07-06 22:57:32'),
('34d8d320-80e9-5ccc-ae30-f0eeec8e537d', '7a0250c3-fa79-44ab-92e1-c6c07843ce26', 'The general commanded a powerful ___ to protect the border from invaders.', '將軍指揮著一支強大的軍隊來保護邊界免受入侵者攻擊。', 'army', 'crowd', 'nation', 'factory', 'army 為名詞，指「軍隊」或「大群」。', '想像士兵們穿著盔甲 (armored) 準備作戰 → army。', '2026-07-07 00:02:57', '2026-07-07 00:02:57'),
('a4830d34-ef7e-53a2-a24b-d284742231a1', 'd7b9d00e-f227-4126-ac79-d6f334d9a9be', 'My ___ gave me a nice birthday present.', '我的姨媽（或姑媽）送了我一份很棒的生日禮物。', 'aunt', 'teacher', 'doctor', 'pilot', 'aunt 為名詞，指女性的親戚。', 'aunt 唸起來像「安特」，聯想姨媽送禮物時很「安」靜。', '2026-07-06 15:43:13', '2026-07-06 15:43:13'),
('2b803576-612d-5e26-8d28-c0e4641eacf5', '318b3888-310a-45fa-9605-7417cd8c50e1', 'My ___ is very clean and has a large window.', '我的臥房非常乾淨，而且有一個大窗戶。', 'bedroom', 'office', 'garage', 'library', '由 bed (床) 與 room (房間) 組成。', 'bed (床) + room (房間) → 睡覺用的房間就是 bedroom。', '2026-07-07 03:00:00', '2026-07-07 03:00:00'),
('b18cd3bb-fb7e-5326-bab5-ec750ecdfab1', 'e12a63d8-276d-4c7c-8a2a-17a6bebecf61', 'The workers use a red ___ to build the wall.', '工人們用紅色的磚塊來蓋這面牆。', 'brick', 'stone', 'pen', 'cup', 'brick 為名詞，指建築用的磚塊。', '想像蓋房子時，一顆一顆紅色的方塊就是 brick。', '2026-07-07 10:03:39', '2026-07-07 10:03:39'),
('7e876686-a593-5713-ba4e-dafd1f25049d', 'bd2fea8b-c2fc-4631-b273-12d27befdc74', 'She is an only ___ in her family.', '她是家中的獨生子/女。', 'child', 'student', 'doctor', 'driver', 'child 為名詞，指未成年者。', 'child 就像「恰爾德」，是一個可愛的小孩。', '2026-07-07 03:41:36', '2026-07-07 03:41:36'),
('77af48ab-4631-5f02-a22c-0a1a0f879d61', 'f614969a-4746-49c7-9048-33dcfe0afda6', 'You should ___ your English skills by reading more books every day.', '你應該透過每天閱讀更多的書來增進你的英文能力。', 'develop', 'borrow', 'forget', 'believe', 'de- (除去) + velop (包覆) → 解開包覆物 → 引申為發展、研發或增進。', '想像學習就像解開一個包裹，讓知識慢慢「發展」出來。', '2026-07-07 03:43:50', '2026-07-07 03:43:50'),
('07a79e71-5cf4-5b73-851e-a105e23af33d', 'd92c4292-0865-4027-acfc-9f07c3b0c7d1', 'He uses a pencil to ___ a picture of a dog.', '他用鉛筆畫一幅狗的圖畫。', 'draw', 'write', 'color', 'make', 'draw 為動詞，表示繪製、畫出。', '想像用筆在紙上「拉」出線條 → 畫圖。', '2026-07-07 11:25:01', '2026-07-07 11:25:01'),
('a1c35c08-1bcf-5303-b38d-9cf92bff930d', '7b283292-e84e-4f48-8418-372c668775e3', 'We don''t have ___ chairs for the guests.', '我們沒有足夠的椅子給客人。', 'enough', 'many', 'some', 'any', '無明顯字根', '形容詞用法：enough + 名詞 (例如：enough chairs)', '2026-07-07 04:01:14', '2026-07-07 04:01:14'),
('8a3adf12-fa83-553c-a9f1-e23b6be5e1a5', '3d3e443a-cbad-40c3-9126-c4bace4edf2f', 'Please remember to ___ your dog before you go to school.', '在你去上學之前，請記得要餵你的狗。', 'feed', 'wash', 'walk', 'find', 'feed 是基本動詞，意為「餵養」或「提供食物」。', '想像餵食時，食物不斷地 feed (餵) 進嘴裡。', '2026-07-07 05:21:56', '2026-07-07 05:21:56'),
('0c905c93-b54b-5657-a832-8f4a29bc2239', 'f270b75d-4cd9-4268-8544-3cfa3a11b997', 'My brother is a ___ boy, and many girls like him.', '我哥哥是一個英俊的男孩，很多女生都喜歡他。', 'handsome', 'heavy', 'noisy', 'sleepy', 'hand (手) + some (具有...性質的) → 意指外表吸引人的。', '看到 handsome 就聯想到帥氣的男主角。', '2026-07-07 14:29:01', '2026-07-07 14:29:01'),
('a5d3af7f-a909-543a-98d3-de7346e27c51', 'a21e47b4-26b8-45c3-ad1d-817a5092e41e', 'The math test was very difficult; ___, many students passed it.', '這場數學考試非常難；然而，許多學生都通過了。', 'however', 'therefore', 'besides', 'finally', 'how (如何) + ever (任何) → 然而', '看到轉折關係（難 vs 通過）時，使用 however。', '2026-07-08 08:18:27', '2026-07-08 08:18:27'),
('d27cf8ba-a03a-5f12-b2e7-8513412ddf3d', '25a33ba6-7721-46f9-ac54-1ce83ca46d50', 'My grandfather is one ___ years old.', '我祖父一百歲了。', 'hundred', 'thousand', 'million', 'dozen', 'cent 代表『百』，常見於 cent (分/百分之...)。', '一百就像是一個滿滿的大圓圈，代表一個完整的數量。', '2026-07-08 08:27:38', '2026-07-08 08:27:38'),
('8e33834d-1700-54dd-bf3d-f1ea2da31379', 'c71bd206-4042-406c-8bc2-46572ad87585', 'We walked ___ the park to enjoy the fresh air.', '我們漫步到公園去呼吸新鮮空氣。', 'to', 'from', 'at', 'in', '表示方向、目的地或對象的介系詞。', 'to → 到 (目的地)', '2026-07-05 10:27:51', '2026-07-05 10:27:51');
